```class Solution {
public:
    string smallestSubsequence(string s) {
        unordered_set<char> charSet(s.begin(), s.end());
        string result;
        for (char c : s) {
            if (charSet.count(c) == 0) continue;
            result += c;
            charSet.erase(c);
        }
        return result;
    }
};
